namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = new();
    public List<string> Steps { get; set; } = new();
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Ingredients = new() { "Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil" },
            Steps = new() { "Preheat oven to 475°F.", "Roll out dough on floured surface.", "Spread crushed tomatoes evenly.", "Add torn mozzarella pieces.", "Bake 10-12 minutes until crust is golden.", "Top with fresh basil and drizzle olive oil." },
            AverageRating = 4.5, RatingCount = 12
        },
        new Recipe
        {
            Id = 2, Title = "Chicken Tikka Masala", Category = "Indian",
            Ingredients = new() { "Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Garlic", "Ginger" },
            Steps = new() { "Marinate chicken in yogurt and spices for 2 hours.", "Grill or pan-fry chicken until charred.", "Sauté garlic and ginger in oil.", "Add tomato sauce and simmer 10 minutes.", "Stir in cream and cooked chicken.", "Simmer 5 more minutes and serve with rice." },
            AverageRating = 4.8, RatingCount = 24
        },
        new Recipe
        {
            Id = 3, Title = "Beef Tacos", Category = "Mexican",
            Ingredients = new() { "Ground beef", "Taco shells", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Taco seasoning" },
            Steps = new() { "Brown ground beef in a skillet.", "Add taco seasoning and water, simmer 5 minutes.", "Warm taco shells in oven.", "Assemble tacos with beef and toppings.", "Serve with salsa and sour cream." },
            AverageRating = 4.2, RatingCount = 8
        },
        new Recipe
        {
            Id = 4, Title = "Pad Thai", Category = "Thai",
            Ingredients = new() { "Rice noodles", "Shrimp", "Eggs", "Bean sprouts", "Peanuts", "Lime", "Fish sauce", "Tamarind paste" },
            Steps = new() { "Soak rice noodles in warm water 30 minutes.", "Make sauce: mix tamarind paste, fish sauce, and sugar.", "Stir-fry shrimp until pink, set aside.", "Scramble eggs in wok.", "Add drained noodles and sauce, toss until coated.", "Add shrimp, bean sprouts, and peanuts. Serve with lime." },
            AverageRating = 4.6, RatingCount = 15
        },
        new Recipe
        {
            Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts",
            Ingredients = new() { "Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract" },
            Steps = new() { "Preheat oven to 425°F. Grease ramekins.", "Melt chocolate and butter together.", "Whisk eggs, sugar, and vanilla until thick.", "Fold chocolate mixture into egg mixture.", "Add flour and fold gently.", "Bake 12-14 minutes until edges are set but center is soft." },
            AverageRating = 4.9, RatingCount = 30
        },
        new Recipe
        {
            Id = 6, Title = "Caesar Salad", Category = "Salads",
            Ingredients = new() { "Romaine lettuce", "Parmesan cheese", "Croutons", "Caesar dressing", "Lemon juice", "Anchovy paste" },
            Steps = new() { "Wash and chop romaine lettuce.", "Make dressing: whisk anchovy paste, lemon juice, garlic, and olive oil.", "Toss lettuce with dressing.", "Top with shaved parmesan and croutons.", "Serve immediately." },
            AverageRating = 4.0, RatingCount = 6
        }
    };

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public IReadOnlyList<Recipe> GetRecipesByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetRecipeById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round(totalStars / recipe.RatingCount, 1);
    }

    public void SubmitRecipe(RecipeSubmission submission)
    {
        var newId = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(new Recipe
        {
            Id = newId,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = submission.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            AverageRating = 0,
            RatingCount = 0
        });
    }
}

