@page "/category/{CategoryName}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models

<PageTitle>@CategoryName Recipes - Recipe Community</PageTitle>

<div class="container py-4">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">@CategoryName</li>
        </ol>
    </nav>

    <h1 class="mb-4">@CategoryName Recipes</h1>

    @if (Recipes.Count == 0)
    {
        <div class="alert alert-info">No recipes found in this category.</div>
    }
    else
    {
        <div class="row g-4">
            @foreach (var recipe in Recipes)
            {
                <div class="col-md-6">
                    <div class="card h-100 shadow-sm">
                        <div class="card-body">
                            <h4 class="card-title">
                                <a href="/recipe/@recipe.Id" class="text-decoration-none">@recipe.Title</a>
                            </h4>
                            <p class="text-muted mb-1">
                                ⭐ @recipe.AverageRating.ToString("0.0") (@recipe.RatingCount ratings)
                            </p>
                            <p class="card-text">@recipe.Ingredients.Count ingredients · @recipe.Steps.Count steps</p>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<Recipe> Recipes { get; set; } = Array.Empty<Recipe>();

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models
@using RecipeCommunity.Components.Shared

<PageTitle>@(Recipe?.Title ?? "Recipe") - Recipe Community</PageTitle>

<div class="container py-4">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            @if (Recipe is not null)
            {
                <li class="breadcrumb-item"><a href="/category/@Recipe.Category">@Recipe.Category</a></li>
                <li class="breadcrumb-item active">@Recipe.Title</li>
            }
        </ol>
    </nav>

    @if (Recipe is null)
    {
        <div class="alert alert-warning">Recipe not found.</div>
    }
    else
    {
        <h1>@Recipe.Title</h1>
        <p class="text-muted">⭐ @Recipe.AverageRating.ToString("0.0") (@Recipe.RatingCount ratings) · @Recipe.Category</p>

        <StarRating RecipeId="@Recipe.Id" />

        <div class="row mt-4">
            <div class="col-md-4">
                <div class="card">
                    <div class="card-header"><h5 class="mb-0">🥘 Ingredients</h5></div>
                    <ul class="list-group list-group-flush">
                        @foreach (var ingredient in Recipe.Ingredients)
                        {
                            <li class="list-group-item">@ingredient</li>
                        }
                    </ul>
                </div>
            </div>
            <div class="col-md-8">
                <div class="card">
                    <div class="card-header"><h5 class="mb-0">📋 Steps</h5></div>
                    <div class="card-body">
                        <ol class="mb-0">
                            @foreach (var step in Recipe.Steps)
                            {
                                <li class="mb-2">@step</li>
                            }
                        </ol>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetRecipeById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Services
@using RecipeCommunity.Models

<PageTitle>Submit a Recipe - Recipe Community</PageTitle>

<div class="container py-4">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">Submit Recipe</li>
        </ol>
    </nav>

    <h1 class="mb-4">📝 Submit Your Recipe</h1>

    @if (_submitted)
    {
        <div class="alert alert-success">
            <h4>Recipe submitted successfully!</h4>
            <p>Your recipe "<strong>@_submission.Title</strong>" has been added to the community.</p>
            <a href="/" class="btn btn-primary">Back to Home</a>
        </div>
    }
    else
    {
        <EditForm Model="_submission" OnValidSubmit="HandleSubmit" class="needs-validation">
            <div class="mb-3">
                <label for="title" class="form-label">Recipe Title</label>
                <InputText id="title" class="form-control" @bind-Value="_submission.Title" placeholder="e.g. Grandma's Apple Pie" />
            </div>

            <div class="mb-3">
                <label for="category" class="form-label">Category</label>
                <InputSelect id="category" class="form-select" @bind-Value="_submission.Category">
                    <option value="">-- Select a category --</option>
                    @foreach (var cat in RecipeService.GetCategories())
                    {
                        <option value="@cat">@cat</option>
                    }
                    <option value="Other">Other</option>
                </InputSelect>
            </div>

            <div class="mb-3">
                <label for="ingredients" class="form-label">Ingredients</label>
                <InputTextArea id="ingredients" class="form-control" rows="5"
                    @bind-Value="_submission.Ingredients"
                    placeholder="One ingredient per line&#10;e.g.&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" />
                <div class="form-text">Enter one ingredient per line.</div>
            </div>

            <div class="mb-3">
                <label for="steps" class="form-label">Steps</label>
                <InputTextArea id="steps" class="form-control" rows="6"
                    @bind-Value="_submission.Steps"
                    placeholder="One step per line&#10;e.g.&#10;Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients" />
                <div class="form-text">Enter one step per line.</div>
            </div>

            <button type="submit" class="btn btn-success btn-lg"
                    disabled="@(string.IsNullOrWhiteSpace(_submission.Title) || string.IsNullOrWhiteSpace(_submission.Category))">
                Submit Recipe
            </button>
        </EditForm>
    }
</div>

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private RecipeSubmission _submission = new();
    private bool _submitted;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(_submission.Title) || string.IsNullOrWhiteSpace(_submission.Category))
            return;

        RecipeService.SubmitRecipe(_submission);
        _submitted = true;
    }
}

